{
  "name": "Health First Colorado Buy-In (QMB, SLMB, QI)",
  "eligibility": {
    "age": 65,
    "income_limits": "These are federal Medicare Savings Programs (MSPs) administered through Health First Colorado. Limits are based on Federal Poverty Level (FPL) and typically updated annually; exact 2026 figures unavailable in sources but structured as: QMB: ≤100% FPL (~$1,275/month single, $1,724 couple); SLMB: 100-120% FPL (~$1,531-$1,830 single, $2,055-$2,190 couple); QI: 120-135% FPL (~$1,831-$2,056 single, $2,460-$2,760 couple). Household size affects limits (higher for larger households); must have Medicare Part A eligibility. Does not vary by standard household size beyond individual/couple but considers dependents in some calculations.[1]",
    "asset_limits": "Yes, resource limits apply (three levels by program): typically $9,090 individual/$13,630 couple (2024 figures; may adjust). Counts: bank accounts, stocks, bonds. Exempt: home/land, one vehicle, personal belongings, life insurance (up to $1,500 face value), burial funds/plots.[1]",
    "other_requirements": ["Must be enrolled in Medicare Part A.", "Colorado resident.", "U.S. citizen or qualified immigrant.", "Not eligible for full Medicaid.", "For QI, funding is limited and first-come, first-served."]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part B premium (~$185/month in 2026), deductibles, copays, coinsurance (covers 20% Medicare does not, providing full coverage). SLMB/QI: Pays only Part B premium; individual pays deductibles, copays, coinsurance.[1]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.healthfirstcolorado.com/apply-now/", "Phone: Contact local county human services office (find via https://cdhs.colorado.gov/counties or 1-800-221-3943)", "Mail/In-person: Local county Department of Human Services office.", "Through Health First Colorado general application."],
    "processing_time": "45-90 days typical for MSPs; varies by county.",
    "waitlist": "QI may have waitlist due to federal funding caps.",
    "forms": ["Health First Colorado Application (online or paper via county offices); no unique form number specified for MSPs—use main Medicaid app and indicate Medicare status."],
    "documents": ["Proof of income (pay stubs, tax returns), Medicare award letter, bank statements/resource proof, ID (SSN, birth certificate), proof of residency, disability determination if applicable."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide via county human services.",
    "regional_variations": "Processing times and office locations vary by county; no benefit differences.",
    "offices_or_providers": ["Apply via any of Colorado's 64 county Departments of Human Services."]
  },
  "official_source": "https://hcpf.colorado.gov/medicaid-buy-program (general Buy-In; MSPs via https://www.healthfirstcolorado.com/)",
  "gotchas": ["Confused with Working Adults/Children with Disabilities Buy-In (different program for disabled under 65, premium-based on income).[2]", "QI has limited federal funding—may close enrollment.", "Must already have Medicare Part A; auto-enrollment not guaranteed.", "Assets include non-exempt items people overlook (e.g., second car).", "Income is countable after deductions; SLMB/QI higher thresholds but no copay coverage.[1][3]"],
  "data_shape_notes": "Tiered by QMB/SLMB/QI with escalating income limits but decreasing benefit generosity; asset-tested unlike some Medicaid Buy-Ins; federal MSP standards uniform but county-administered."
}

{
  "name": "Meals on Wheels Colorado",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits statewide; some providers use sliding scale fees based on income (e.g., Fort Collins: reduced fees with gross monthly income verification, max $6.50-$7.50/meal). Contributions suggested but not required (e.g., $2.50/meal in Douglas County, $3.50/meal in Mesa County). No one denied for inability to pay.[1][2][3][5][7]",
    "asset_limits": "No asset limits mentioned across providers.",
    "other_requirements": ["Homebound or unable to shop/prepare meals safely.", "May qualify under 60 with disability proof, medical referral, or specific circumstances (varies by provider).", "Residency in service area.", "Family caregivers in same home may qualify in some areas (e.g., Douglas, Broomfield)."][1][2][3][5][6]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals (1/3 daily nutrients): hot/fresh weekdays (e.g., entrée, vegetables, fruit, bread, milk); some offer frozen weekend meals or 5 frozen meals/week. Low sodium/sugar/fat. Delivered Mon-Fri, ~11am-12:30pm by volunteers. No fixed hours/dollar value; 1 meal/day typical.[1][3][5][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone/email by region (e.g., VOA Denver metro: 303-294-0111, mdeherrera@voacolorado.org; Larimer: 970-472-9630, larimer@voacolorado.org; Lafayette/Louisville/Erie/Superior: 303-665-0566, coalcreekmow.org; Mesa County: call office).", "Download/mail application (e.g., Mesa County Home Delivered Meals application).", "Intake form over phone (e.g., Mesa County Congregate).", "Contact local provider for assessment/referral."[1][2][6][7]],
    "processing_time": "Varies; office call after application received to schedule start. Douglas County: reassessment after 90 days to restart.[3][7]",
    "waitlist": "Possible; Douglas County has waiting lists. Mesa County: longer wait times due to application influx.[3][7]",
    "forms": ["Home Delivered Meals application (Mesa County).", "Congregate Intake Form (Mesa County).", "Assessment/application required by most providers.[4][7]"],
    "documents": ["Proof of age/disability if under 60 or needed.", "Income verification for sliding scale (some, e.g., Fort Collins).", "Residency proof, medical referral if applicable. Contact provider for exact needs.[2][4][5]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "County-specific providers; not uniform across Colorado (e.g., VOA: Adams, Arapahoe, Clear Creek, Denver, Douglas, Gilpin, Jefferson, Larimer; Broomfield; Fort Collins; Mesa County; Lafayette/Louisville/Erie/Superior).",
    "regional_variations": "Age (60+ standard, 62+ in Fort Collins); fees/sliding scales; meal types (frozen weekly in Douglas); weekend meals (some yes); contacts differ; wait times vary.[1][2][3][5][6][7]",
    "offices_or_providers": ["VOA Colorado (multiple counties): voacolorado.org/services/meals-on-wheels.", "Meals on Wheels Fort Collins: mealsonwheelsfc.org.", "Douglas County Senior Center.", "Broomfield: broomfield.org/371/Meals-on-Wheels.", "Mesa County: mealsonwheelsmesacounty.org.", "Coal Creek MOW (Lafayette etc.): coalcreekmow.org."[1][2][3][5][6][7]]
  },
  "official_source": "No single statewide .gov site; local providers via mealsonwheelsamerica.org/find-meals-and-services/ for search.[4]",
  "gotchas": ["Not centralized—must contact specific regional provider; eligibility/assessments vary (homebound key, not just age).", "Suggested contributions but no one denied; sliding scales need income proof.", "Waitlists common; no weekends standard (limited frozen).", "Restart after 90 days requires reassessment.", "Under 60 needs disability/medical proof.", "Short-term post-hospital available in some areas."[1][2][3][5][7]],
  "data_shape_notes": "Decentralized network of local providers with county-specific eligibility, contacts, fees, and wait times; no uniform state program or income tables."
}

{
  "name": "Alzheimer’s Disease and Related Dementia (ADRD) Respite",
  "eligibility": {
    "age": 60,
    "income_limits": "Varies by Medicaid financial eligibility for programs like EBD Waiver; specific dollar amounts not listed in sources but tied to SSI levels and state-determined limits for limited income/assets. No fixed table provided for ADRD respite specifically.",
    "asset_limits": "Medicaid-linked programs require limited assets; exact counts/exemptions (e.g., primary home often exempt) follow state Medicaid rules but not detailed for ADRD respite.",
    "other_requirements": ["Colorado resident", "Diagnosis of Alzheimer's or related dementia", "Care recipient frail or at risk of nursing home placement (NFLOC: assistance with 2+ ADLs or moderate cognitive/behavioral supervision needs)", "For voucher programs: family caregiver providing unpaid care", "For GUIDE: traditional Medicare (not Advantage), living in home/assisted living/memory care (not nursing home/hospice/PACE)", "County residency for some local programs (e.g., Weld County)"]
  },
  "benefits": {
    "type": "service",
    "value": "Respite vouchers for self-directed family caregiver payments to respite providers; in-home respite care; 24/7 support line; comprehensive assessments; support for caregivers to delay nursing home placement. Specific hours/dollars not quantified in sources.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Colorado Respite Coalition Self-Directed Family Respite Voucher Program (apply via https://archrespite.org/ta-center-for-respite/respite-voucher-programs/apply-for-state-lifespan-respite-voucher-programs/ marker for CO)", "Dial 211 for local ADRD resources (https://www.211colorado.org/adrd/)", "For GUIDE: Call CU Medicine GUIDE at 303-724-3141 (https://www.cumedicine.us/services/guide)", "Local human services (e.g., Weld County programs)"],
    "processing_time": "Not specified; GUIDE involves intake visits and Medicare approval after initial contact.",
    "waitlist": "Possible for Medicaid EBD Waiver due to limited slots; not specified for respite voucher.",
    "forms": ["Level of Care (LOC) Determination Screening Instrument for EBD-related eligibility"],
    "documents": ["Proof of residency", "Dementia diagnosis", "Medicare card (for GUIDE)", "Income/asset documentation for Medicaid-linked eligibility", "Information on person with dementia and caregiver"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Some local programs county-specific (e.g., Weld County requires residency)",
    "regional_variations": "Administered via Colorado Respite Coalition statewide voucher; local Area Agencies on Aging (AAAs) or counties (e.g., Weld) may have variations in providers/wait times; GUIDE via CU Medicine/UCHealth (Denver-area focus)",
    "offices_or_providers": ["Colorado Respite Coalition", "CU Medicine GUIDE (Denver)", "211 Colorado (statewide)", "Local departments of human services (e.g., Weld County)"]
  },
  "official_source": "https://archrespite.org/ta-center-for-respite/respite-voucher-programs/apply-for-state-lifespan-respite-voucher-programs/ (Colorado Respite Coalition); https://www.211colorado.org/adrd/",
  "gotchas": ["Not an entitlement; waitlists possible via linked Medicaid waivers", "Dementia diagnosis alone insufficient—must meet NFLOC (2+ ADLs or cognitive needs)", "GUIDE requires traditional Medicare only, home-based living", "County-specific residency for some supports", "Limited slots; call 211 first for local options", "Not available in nursing homes or certain facilities"],
  "data_shape_notes": "Statewide voucher via coalition but funnels through local AAAs/counties with residency rules; ties to Medicaid EBD Waiver for some; multiple overlapping programs (voucher, GUIDE, local); no fixed income table or hours in sources"
}

{
  "name": "Colorado Legal Services (Seniors)",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income or asset limits for seniors 60+ in many regions (e.g., Larimer County explicitly states none); statewide preference for low-income based on federal poverty guidelines, but seniors qualify regardless if resources available[1][2][3]",
    "asset_limits": "No asset limits mentioned for seniors; not required in documented examples[2]",
    "other_requirements": ["Must be Colorado resident", "Civil legal issues only (no criminal or traffic)", "Complete intake screening process", "Some regions require residency in specific counties served by local office (e.g., Larimer, Pueblo, or Metro Denver counties like Adams, Arapahoe, etc.)[1][2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal aid including: advice from attorney, assistance filing cases, full court representation; specific senior issues: estate planning, wills/trusts, power of attorney, guardianship/conservatorship, advance directives, liens, consumer issues, landlord/tenant disputes, Medicaid/Medicare, government benefits (SNAP, SSI), housing, family law, debt/bankruptcy, tax controversies, immigration for eligible categories; holistic support via social workers in some areas (Denver, Colorado Springs)[1][2][3][4]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Online pre-apply: https://www.coloradolegalservices.org/get-help/[3][7]", "Phone: Call local office (statewide intake process required; specific numbers via website or local AAA)[1][3][7]", "In-person: Visit nearby office (13 offices statewide; e.g., Pueblo County via local human services, Larimer via Senior Access Point)[1][2][7]", "Mail: Not specified as primary; use intake process via phone/online"],
    "processing_time": "Team contacts after application to assess eligibility; no specific timeline stated",
    "waitlist": "Limited resources may result in turning away cases; prioritization for high-need low-income seniors[2][5][6]",
    "forms": ["Intake process required (no specific form name/number; pre-apply online or call)[2][3][7]"],
    "documents": ["Not explicitly listed; prepare ID, proof of residency, income details for screening, case-related documents (e.g., eviction notice, benefits denial); available in native language via call/visit[3][4][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Served via 13 CLS offices and 16 Area Agencies on Aging (AAA) regions; some offices county-specific (e.g., Larimer residents only for local project, Metro Denver counties: Adams, Arapahoe, Broomfield, etc.)[2][5][8]",
    "regional_variations": "Case types vary by office resources (e.g., not all handle foreclosures); services via local AAAs contracting private attorneys/legal orgs like CLS; social workers in Denver/Colorado Springs; preference/availability differs (e.g., Pueblo emphasizes low-income preference)[1][2][4][5]",
    "offices_or_providers": ["13 CLS offices statewide", "21 legal assistance providers via 16 AAAs", "Examples: Pueblo County Human Services, Larimer Senior Access Point, Metro Denver offices[1][2][5][8]"]
  },
  "official_source": "https://www.coloradolegalservices.org",
  "gotchas": ["Not a hotline for quick advice—must complete full intake screening[2][3][7]", "Limited resources mean not all cases accepted, even if eligible; turn away rate high[2][6]", "Case types vary by local office—contact specific region first[2][5]", "Prioritizes high social/economic need; low-income get preference but seniors 60+ often qualify without strict limits[1][3][5]", "Operates alongside separate Older Americans Act-funded network via Disability Law Colorado/AAAs, which may overlap or refer[5]"],
  "data_shape_notes": "Seniors 60+ have priority access without strict income/asset tests unlike general low-income program; delivered via statewide CLS offices + regional AAA-contracted providers; services/case acceptance varies by 16 AAA regions and office resources"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a skilled nursing home or licensed assisted living residence in Colorado.", "Services also extend to relatives, friends, facility staff, or any concerned individual about such residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints on resident rights violations (e.g., privacy, dignity, abuse), care issues (e.g., medications, hygiene), transfers/discharges; investigation, problem-solving, resource linkage, education, and consultation. Services are free, confidential, and resident-directed.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Visit https://www.coombudsman.org and use 'Find an Ombudsman' tool for local contacts.", "Contact local offices (e.g., Boulder County: implied via county site; Pueblo County: 719-601-6282 or dmason@srda.org).", "Phone or email varies by local program; statewide site provides directory."],
    "processing_time": "Immediate response for complaints; no formal processing as it's advocacy service, not benefits enrollment.",
    "waitlist": null,
    "forms": ["No specific forms required; contact ombudsman directly to report concerns."],
    "documents": ["No documents needed to initiate contact; for action on behalf (if resident cognitively impaired), power of attorney may direct."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of licensed skilled nursing homes and assisted living facilities in Colorado.",
    "regional_variations": "Operates via network of local offices with recruited/trained staff and volunteers; providers differ by area (e.g., Boulder County LTCO Program, Pueblo SRDA-managed).",
    "offices_or_providers": ["Statewide network via https://www.coombudsman.org 'Find an Ombudsman'; examples: Boulder County, Pueblo SRDA."]
  },
  "official_source": "https://www.coombudsman.org",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy for rights in facilities; requires resident direction (or POA if impaired); anyone can contact but action is resident-led; only covers licensed nursing homes/assisted living, not other settings like home care.", "Confidentiality means no action without resident permission."],
  "data_shape_notes": "no income/asset/age test; open to residents/families/public; regionally delivered via local ombudsman offices; advocacy-only, complaint-driven service."
}
